#include <vector>
#include <algorithm>
#include <numeric>
#include <climits>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;

    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unite(int u, int v) {
        u = find(u);
        v = find(v);
        if (u == v) return false;
        if (rank[u] < rank[v]) {
            parent[u] = v;
        } else {
            parent[v] = u;
            if (rank[u] == rank[v]) {
                rank[u]++;
            }
        }
        return true;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components > 1) {
        return -1;
    }

    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    long long low = 1;
    long long high = 1e18;
    long long result = -1;

    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu_check(n);
        int components_check = n;
        int used_k = 0;

        for (const auto& e : must_edges) {
            dsu_check.unite(e[0], e[1]);
            components_check--;
        }

        for (const auto& e : optional_edges) {
            long long s = e[2];
            if (s >= mid) {
                if (dsu_check.unite(e[0], e[1])) {
                    components_check--;
                }
            } else if (2 * s >= mid && used_k < k) {
                if (dsu_check.unite(e[0], e[1])) {
                    components_check--;
                    used_k++;
                }
            }
        }

        if (components_check == 1) {
            result = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return result;
}

